sys_variable_value.value:
(function(outputs, steps, params, stepResult, assertEqual) {
    var tableName = 'x_1839224_chroma_0_chromatech_sold_products'; // Update with your table name
    var errors = [];

    // Define expected configuration
    var expectedFields = {
        'product_name': 'string',
        'serial_number': 'string',
        'sold_to': 'reference',
        'date_sold_on': 'glide_date_time',
        'product_type': 'choice',
        'cost': 'price',
        'manufacturing_date': 'glide_date_time',
        'warranty_period_months': 'integer',
        'is_extended_warranty': 'boolean',
        'warranty_extending_date': 'glide_date_time',
        'warranty_expiring_at': 'glide_date_time'
    };

    var expectedChoices = ['Air Conditioners', 'Coolers', 'Ceiling Fans'];

    // 1. Verify Field Types
    for (var field in expectedFields) {
        var grDict = new GlideRecord('sys_dictionary');
        grDict.addQuery('name', tableName);
        grDict.addQuery('element', field);
        grDict.query();

        if (grDict.next()) {
            if (grDict.internal_type.toString() !== expectedFields[field]) {
                errors.push("Field '" + field + "' type mismatch: expected " + expectedFields[field] + ", found " + grDict.internal_type);
            }
        } else {
            errors.push("Field '" + field + "' not found on table '" + tableName + "'.");
        }
    }

    // 2. Verify Choice Values for 'Product Type'
    var grChoice = new GlideRecord('sys_choice');
    grChoice.addQuery('name', tableName);
    grChoice.addQuery('element', 'product_type');
    grChoice.addQuery('inactive', false);
    grChoice.query();

    var actualChoices = [];
    while (grChoice.next()) {
        actualChoices.push(grChoice.label.getDisplayValue());
    }

    expectedChoices.forEach(function(choice) {
        if (actualChoices.indexOf(choice) === -1) {
            errors.push("Missing Choice Value: '" + choice + "' in Product Type.");
        }
    });

    // 3. Final Result Handling
    if (errors.length === 0) {
        stepResult.setOutputMessage("Success: All fields and types verified.");
        stepResult.setSuccess();
        return true;
    } else {
        stepResult.setOutputMessage("Failure:\n" + errors.join('\n'));
        stepResult.setFailed();
        return false;
    }

})(outputs, steps, params, stepResult, assertEqual);
